	public const string AuthenticationServiceDescription = "SR.M('\r\n    /// <code>\r\n    /// //С помощью данного сервиса мы можем получить текущего пользователя,\r\n    /// //получить информацию о авторизованных сессиях. Так же предоставляется возможность\r\n    /// //удалять сессии.\r\n    /// //запишем сервис в переменную, чтобы с ним легче было работать\r\n    /// var service = PublicAPI.Services.Authentication;\r\n    /// \r\n    /// //для получения текущего пользователя используйте функцию GetCurrentUser()\r\n    /// var currentUser = service.GetCurrentUser();\r\n    /// \r\n    /// //для получения информации о активных авторизированных сессиях используйте функцию GetActiveSessions()\r\n    /// var activeSessions = service.GetActiveSessions();\r\n    /// \r\n    /// //для получения информации о авторизированных сессиях используйте функцию GetSession(filter),\r\n    /// //где filter - экземпляр класса AuthenticatedSessionFilter. Данный фильтр предоставляет возможность\r\n    /// //фильтровать по двум полям:\r\n    /// //1.bool OnlyActive - выбирать только активные сессии;\r\n    /// //2.bool OnlyConcurrentUsers - выбирать только сессии пользователей с конкурентными лицензиями.\r\n    /// //Так же вместо filter можно передать null\r\n    /// var sessions = service.GetSessions(null); \r\n    /// \r\n    /// //чтобы удалить сессию по её тикету, используйте функцию RemoveSession(ticketId)\r\n    /// service.RemoveSession(activeSession.First().TicketUid);\r\n    /// \r\n    /// //чтобы удалить все авторизованные сессии пользователя, используйте функцию RemoveAllUserSessions(userId)\r\n    /// service.RemoveAllUserSessions(user.Id);\r\n    /// </code>')";

	public const string BlobStoreDescription = "SR.M('\r\n    /// <code>\r\n    /// //С помощью данного сервиса мы можем управлять хранилищем бинарных данных:\r\n    /// //записывать, получать и удалять значения\r\n    /// \r\n    /// //запишем сервис в переменную, чтобы с ним легче было работать\r\n    /// var service = PublicAPI.Services.BLOBStore; \r\n    /// \r\n    /// //для записи данных используйте функию Save(key, value),\r\n    /// //где key - это ключ, по которому произойдет запись в базу,\r\n    /// //value - байтовый массив записываемых данных\r\n    /// service.Save(key, value);\r\n    /// \r\n    /// //для загрузки записанного значения используйте функцию LoadOrNull(key)\r\n    /// var myValue = service.LoadOrNull(key);\r\n    /// \r\n    /// //для удаления записанного значения используйте функцию Remove\r\n    /// service.Remove(key); \r\n    /// </code>')";

	public const string DocumentGeneratorDescription = "SR.M('\r\n    /// <para>\r\n    /// <seealso href=\"http://www.elma-bpm.ru/kb/article-393.html\">Двойная генерация по шаблону</seealso>    \r\n    /// </para>\r\n    /// <code>\r\n    /// //Пример кода взят из статьи в базе знаний, посвящённой двойной генерации документа\r\n    /// <![CDATA[\r\n    /// var version = InterfaceActivator.Create<DocumentVersion>();\r\n    /// version.Document = context.Dokument;\r\n    /// var versionFile = Locator.GetServiceNotNull<IDocumentFileManager>().GetFileByDocumentId(context.Dokument.Id); \r\n    /// var file = Locator.GetServiceNotNull<ITemplateFileManager>().CreateFromTemplate(versionFile.Id); \r\n    /// // Создаем генератор \r\n    /// var generator = PublicAPI.Services.DocumentGenerator.Create(file);\r\n    /// // Генерируем документ \r\n    /// generator.Generate(context); \r\n    /// // Сохраняем файл сгенерированного документа \r\n    /// Locator.GetServiceNotNull<IFileManager>().SaveFile(file); \r\n    /// // Записываем результат в переменную \r\n    /// version.File=file;\r\n    /// version.Name = \"версия из генерации\";\r\n    /// //устанавливаем статус версии Текущая\r\n    /// version.Status = DocumentVersionStatus.Current;\r\n    /// version.File.Name=\"имя файла2.rtf\";\r\n    /// context.Dokument.Versions.Add(version);\r\n    /// context.Dokument.Save();\r\n    /// ]]>\r\n    /// </code>')";

	public const string FileServiceDescription = "SR.M('\r\n    /// <code>\r\n    /// //С помощью данного сервиса можно сохранять и загружать файлы, переименовывать файлы,\r\n    /// //узнать существование файла, размер файла, шифровать и расшифровывать файлы.\r\n    /// //Работа с файлами ведёться в хранилище\r\n    /// \r\n    /// //запишем сервис в переменную, чтобы с ним легче было работать\r\n    /// var service = PublicAPI.Services.File;\r\n    /// \r\n    /// //Чтобы сохранить файл, используйте функцию SaveFile(binaryFile)\r\n    /// //Данная функция возвращает идентификатор файла в строковом представлении\r\n    /// var stringId = service.SaveFile(binaryFile);\r\n    /// \r\n    /// //Чтобы загрузить файлы, используйте следующие функции:\r\n    /// //1.LoadFile(id) - загрузка одного файла по идентификатору\r\n    /// var file = service.LoadFile(id);\r\n    /// \r\n    /// //2.LoadFiles(idList) - загрузка списка файлов по идентификаторам\r\n    /// //idList - массив идентификаторов файлов\r\n    /// var files = service.LoadFiles(idList);\r\n    /// \r\n    /// //Чтобы проверить существование файла, используйте функцию FileExists(id)\r\n    /// var fileExists = service.FileExists(id);\r\n    /// \r\n    /// //Чтобы узнать размер файла, используйте функцию FileSize(id)\r\n    /// var fileSize = service.FileSize(id);\r\n    /// \r\n    /// //Чтобы переименовать файл, используйте функцию RenameFile(id, fileName)\r\n    /// var newFileName = service.RenameFile(id, fileName);\r\n    /// \r\n    /// //Чтобы скопировать файл, используйте функцию CopyFile(sourceBinaryFile)\r\n    /// var newBinaryFile = service.CopyFile(sourceBinaryFile);\r\n    /// \r\n    /// //Чтобы зашифровать файл, используйте функцию Encrypt(file, password, salt)\r\n    /// service.Encrypt(file, password, salt);\r\n    /// \r\n    /// //Чтобы расшифровать файл, используйте функцию Decrypt(file, password)\r\n    /// var decryptedBinaryFile = service.Decrypt(file, password);\r\n    /// \r\n    /// //Чтобы отменить шифрование файла, используйте функцию CancelEncrypt(file, password)\r\n    /// service.CancelEncrypt(file, password);\r\n    /// </code>')";

	public const string ProductionCalendarDescription = "SR.M('\r\n    /// <code>\r\n    /// // Сервис производственного календаря позволяет непосредственно, или через вычислитель календаря: \r\n    /// // - Получить дату начала недели от временной точки\r\n    /// // - Получить название месяца от временной точки\r\n    /// // - Проверить на рабочий день\r\n    /// // - Получить рабочие дни недели\r\n    /// // - Получить количество рабочих дней за период\r\n    /// // - Получить начало рабочего времени для временной точки\r\n    /// // - Получить окончание рабочего времени для временной точки\r\n    /// // - Получить продолжительность базового рабочего дня\r\n    /// // - Получить продолжительность рабочего дня от временной точки\r\n    /// // - Получить количество рабочего времени за период\r\n    /// // - Рассчитать срок\r\n    /// \r\n    /// // Запиcать сервис в переменную, для удобства работы с ним\r\n    /// var service = PublicAPI.Services.ProductionCalendar;\r\n    /// \r\n    /// // Получить вычислитель агрегированного производственного календаря\r\n    /// // Для этого необходимо передать в метод максимальное количество информации для агрегации\r\n    /// // Пользователь системы - при агрегации данных производственного календаря будут учтены индивидуальные настройки производственного календаря пользователя, его отгулы, отпуск и прочая информация\r\n    /// // Сущность - при агрегации данных производственного календаря будут учтены данные календаря соответствующие сущности, например календарь процесса, проекта и так далее\r\n    /// // Настройки часового пояса - по умолчанию вычислитель агрегированного производственного календаря будет настроен в серверном часовом поясе, при необходимости использовать метод, принимающий настройки часового пояса в качестве параметра\r\n    /// var productionSchedule = service.GetProductionSchedule(пользователь, сущность);\r\n    /// // или\r\n    /// var productionSchedule = service.GetProductionSchedule(пользователь, сущность, настройки часового пояса);\r\n    ///\r\n    /// // Получить вычислитель глоабльного производственного календаря\r\n    /// // Настройки часового пояса - по умолчанию вычислитель агрегированного производственного календаря будет настроен в серверном часовом поясе, при необходимости использовать метод, принимающий настройки часового пояса в качестве параметра\r\n    /// var productionSchedule = service.GetGlobalProductionSchedule();\r\n    /// // или\r\n    /// var productionSchedule = service.GetGlobalProductionSchedule(настройки часового пояса);\r\n    /// \r\n    /// // При использовании часовых поясов важно помнить о том, что передаваемое в методы вычислителя время должно быть в часовом поясе среды выполнения\r\n    /// // В 99% для выполнения этого условия ничего делать не нужно, но если по какой-либо причине условия не выполнилось - использовать методы трансформации времени статического класса EleWise.ELMA.TZ\r\n    /// \r\n    /// // Все методы расчета сервиса работают с учетом глобального производственного календаря в серверном часовом поясе и допустимы к использованию только для систем, работающих в одном часовом поясе, с единственным, глоабльным, производственным календарем\r\n    /// // Рекомендуется использовать методы вычислителя полученного посредством методов описанных выше\r\n    /// \r\n    /// // Проверить, является ли день рабочим\r\n    /// var isWorkingDay = service.IsWorkDay(время);\r\n    /// \r\n    /// // Получить срок от интервала - формата TimeSpan\r\n    /// var deadlineByTimeSpan = service.EvalTargetTime(время начала, интервал времени);\r\n    /// \r\n    /// // Получить срок от интервала в часах формат - double\r\n    /// var deadlineByHours = service.EvalTargetTime(время начала, интервал времени в часах);\r\n    /// \r\n    /// // Добавить количество дней и получить время начала рабочего дня (срока) с учетом календаря (с учетом рабочих дней, но без учета рабочего времени в рабочем дне)\r\n    /// var deadlineByDays = service.AddDays(время начала, интервал времени в днях)\r\n    ///\r\n    /// // Получить количество рабочего времени за период в формате TimeSpan, где\r\n    /// // Days - количество рабочих дней (не количество рабочих часов переведенное в дни, учитывается рабочий день без учета продолжительности рабочего времени)\r\n    /// // Hours, Minutes, Seconds - рабочее время в часах\r\n    /// // Например, за период с ПН по СР при условии что ПН, ВТ, СР - рабочие дни вернется TimeSpan, где\r\n    /// // Days == 1 (это вторник), остальное это рабочее время за ПН + рабочее время за СР\r\n    /// var timeSpan = service.EvalWorkTimeSpanDifference(начало периода, конец периода);\r\n    /// \r\n    /// // Получить количество рабочего времени за период в формате TimeSpan - количество часов рабочего времени в формате TimeSpan\r\n    /// var timeSpanByHours = service.EvalWorkTimeDifference(начало периода, конец периода);\r\n    /// \r\n    /// // Получить количество рабочего времени за период в часах - формат double\r\n    /// var doubleByHours = service.EvalWorkTimeHoursDifference(начало периода, конец периода);\r\n    ///\r\n    /// // Получить время начала рабочего дня\r\n    /// var workingTimeStart = service.GetWorkTimeStart(время);\r\n    /// \r\n    /// // Получить время окончания рабочего дня\r\n    /// var workingTimeEnd = service.GetWorkTimeEnd(время);\r\n    /// \r\n    /// // Получить продолжительность базового рабочего дня\r\n    /// var baseWorkingDayDuration = service.GetWorkTimeInDay();\r\n    /// \r\n    /// // Получить продолжительность базового рабочего дня\r\n    /// var baseWorkingDayDuration = service.GetWorkTimeInDay(время);\r\n    ///\r\n    /// // Получить продолжительность базового рабочего дня в минутах\r\n    /// var minutesInDay = service.MinutesInDay();\r\n    ///\r\n    /// // Получить продолжительность базового рабочего дня в минутах\r\n    /// var minutesInDay = service.MinutesInDay(время);\r\n    /// </code>')";

	public const string AvailableTimeSlotsServiceDescription = "SR.M('\r\n    /// <code>\r\n    /// //С помощью данного сервиса мы можем получать свободное время пользователей\r\n    /// \r\n    /// //Загрузить пользователей, свободное время которых хотим получить\r\n    /// var users = PublicAPI.Portal.Security.User.FindByIdArray(new long[] { 1, 3 });\r\n    /// //Указать сроки, за которые хотим получить свободное время пользователей\r\n    /// var timeSlots = new[] { new TimeSlot(new DateTime(2019, 6, 19, 8, 0, 0), new DateTime(2019, 6, 19, 18, 0, 0)) };\r\n    /// //Получить свободное время пользователей\r\n    /// var availableTimeSlots = PublicAPI.Services.AvailableTimeSlotsService.GetIntervals(users, timeSlots);\r\n    /// \r\n    /// </code>')";

	public const string SchedulerDescription = "SR.M('\r\n    /// <code>\r\n    /// //С помощью данного сервиса мы можем запускать уже существующие триггеры\r\n    /// //Идентификаторы работы и триггера можно узнать в веб части (Администрирование -> Система -> Планировщик)\r\n    /// \r\n    /// //запуск триггера с передачей гуидов\r\n    /// PublicAPI.Services.Scheduler.Run(new Guid(\"*тут гуид работы*\"), new Guid(\"*тут гуид тригера*\"));\r\n    /// \r\n    /// //запуск триггера с передачей строк\r\n    /// PublicAPI.Services.Scheduler.Run(\"*тут гуид работы*\", \"*тут гуид тригера*\"); \r\n    /// </code>')";

	public const string SecurityServiceDescription = "SR.M('\r\n    /// <code>\r\n    /// //С помощью данного сервиса можно проверять на наличие привилегий у пользователей и запускать какие-либо\r\n    /// //действия от лица определённого пользователя с ограниченными или полными правами\r\n    /// \r\n    /// //запишем сервис в переменную, чтобы с ним легче было работать\r\n    /// var service = PublicAPI.Services.Security;\r\n    /// \r\n    /// //Чтобы проверить наличие привилегий, используйте следующие функции:\r\n    /// //1.HasPermission(user, permission) - проверить наличие привилегии у определённого пользователя\r\n    /// var hasPermission = service.HasPermission(user, permission);\r\n    /// \r\n    /// //2.HasPermission(permission) - проверить наличие привилегии у текущего пользователя\r\n    /// var hasPermission = service.HasPermission(permission);\r\n    /// \r\n    /// //3.HasPermission(user, permission, permissionSubject, skipAdmin) - проверить наличие привилегии у пользователя относительно экземпляра объекта\r\n    /// var hasPermission = service.HasPermission(user, permission, permissionSubject, skipAdmin);\r\n    /// \r\n    /// //4.HasPermission(permission, target, skipAdmin) - проверить наличие привилегии у текущего пользователя относительно экземпляра объекта\r\n    /// var hasPermission = service.HasPermission(permission, target, skipAdmin);\r\n    /// \r\n    /// //Чтобы проверить возможность проверки на наличие привилегии, используйте функцию CanCheckPermission(permission, target)\r\n    /// var canCheck = service.CanCheckPermission(permission, target);\r\n    /// \r\n    /// //Чтобы запустить код с теми или иными привилегиями используйте следующие функции:\r\n    /// //1.RunWithElevatedPrivilegies(action) - запустить код с повышенными привилегиями.\r\n    /// service.RunWithElevatedPrivilegies(() => \r\n\t///\t\t{\r\n\t///             Console.WriteLine(\"Это работает!\");\r\n\t///     });\r\n\t/// \r\n    /// //2.RunWithElevatedPrivilegiesAndWithDeleted(action) - запустить без фильтрации по пермишеннам и удалению\r\n    /// service.RunWithElevatedPrivilegiesAndWithDeleted(() => \r\n    ///\t\t{\r\n    ///             Console.WriteLine(\"Это работает!\");\r\n    ///     });\r\n    /// \r\n    /// //3.RunWithUsualPrivilegies(action) - запустить с обычными привилегиями\r\n    /// service.RunWithUsualPrivilegies(() => \r\n    ///\t\t{\r\n    ///             Console.WriteLine(\"Это работает!\");\r\n    ///     });\r\n    /// \r\n    /// //Чтобы запустить код от лица какого-либо пользователя используйте следующие функции:\r\n    /// //1.RunBySystemUser(action) - запустить код от имени системного пользователя с повышенными привилегиями.\r\n    /// service.RunBySystemUser(() => \r\n    ///\t\t{\r\n    ///             Console.WriteLine(\"Это работает!\");\r\n    ///     });\r\n    /// \r\n    /// //2.RunByUser(user, action) - запустить код от имени пользователя\r\n    /// service.RunByUser(user, () => \r\n    ///\t\t{\r\n    ///             Console.WriteLine(\"Это работает!\");\r\n    ///     });\r\n    /// </code>')";

